INSERT INTO `productos` VALUES (42,1,1,'Plan chatbot ventas gratis','plan de ventas gratis por 14 dias tendras tu propio robot vendedor 24/7 \nManejo de productos \nCategorias\nCotizacion\nPedidos\nNotificaciones\nAgenda llamadas , citas etc\naumenta conversiones',NULL,0.00,0.00,'4585','44575454',1,NULL,NULL,1000,NULL,NULL,NULL,NULL,NULL,'PUBLISHED',NULL,NULL,NULL,'2026-05-03 17:13:27'),(45,1,1,'Jetski','Es de alta velocidad , 4 tiempos diseñada para ganar','PRODUCT',20000.00,0.00,'','',1,NULL,NULL,25,NULL,NULL,NULL,NULL,NULL,'PUBLISHED',NULL,NULL,NULL,'2026-05-03 17:13:31'),(46,1,1,'Diseño Sitios web ','🖥️ Diseño de Sitios Web Profesionales\n\nTransforma tu presencia digital con un sitio web moderno, rápido y diseñado para convertir visitantes en clientes. Creamos experiencias visuales atractivas y funcionales, adaptadas a cualquier dispositivo y enfocadas en resultados reales para tu negocio.\n\nNuestros desarrollos combinan diseño estratégico, tecnología actual y optimización SEO para que tu marca destaque frente a la competencia.\n\n🚀 ¿Qué incluye?\n🎨 Diseño 100% personalizado\n📱 Adaptación completa a móviles (responsive)\n⚡ Carga rápida y optimización de rendimiento\n🔒 Seguridad y buenas prácticas\n🧩 Integración con sistemas (APIs, ERP, CRM)\n📈 Optimización para posicionamiento en Google\n💬 Incluye Chatbot Inteligente de Ventas\n\nConvierte tu sitio en una máquina de ventas automática con un chatbot integrado que:\n\n🤖 Responde a tus clientes 24/7\n🟢 Detecta clientes curiosos, interesados y listos para comprar\n💰 Automatiza respuestas y procesos de venta\n📊 Captura leads y datos de contacto\n🔗 Se integra con WhatsApp, CRM y sistemas internos\n🧠 ¿Por qué es diferente?\n\nNo solo creamos páginas web… desarrollamos herramientas que trabajan por ti, ayudándote a vender incluso cuando estás desconectado.\n\n📞 Call to Action\n\nImpulsa tu negocio hoy mismo.\n👉 Solicita tu sitio web con chatbot de ventas y empieza a convertir visitas en ingresos.','SERVICE',0.00,0.00,'','',0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,'PUBLISHED',NULL,NULL,NULL,'2026-05-03 17:13:37');
