/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `tr_create_contact_on_user_insert` BEFORE INSERT ON `users` FOR EACH ROW BEGIN
    DECLARE v_contact_id BIGINT;
    DECLARE v_uuid VARCHAR(255);
    IF NEW.contact_id IS NULL THEN
        SET v_uuid = UUID();
        INSERT INTO contacts (uuid, name, email, tenant_id, company_id, is_active, created_at, type, stage)
        VALUES (v_uuid, CONCAT(NEW.nombres, ' ', NEW.apellidos), NEW.email, NEW.customer_id, NEW.company_id, 1, NOW(), 'CUSTOMER', 'NEW');
        SET v_contact_id = LAST_INSERT_ID();
        SET NEW.contact_id = v_contact_id;
    END IF;
END */;;
DELIMITER ;
